import React from "react"
import Header from "./components/Header"
import Footer from "./components/Footer"
import Items from "./components/Items"


class App extends React.Component {
    constructor(props) {
        super(props)
        this.state = {
            orders:[],
            items: [
                {
                    id: 1,
                    title: "Стул сірий",
                    img: "chair.jpg",
                    desc: "lorem5 sdgfwfdgwdfgwd rwertwe,rgfwergew ",
                    category: "chair",
                    price: "525"
                },
                {
                    id: 2,
                    title: "Стол",
                    img: "table.jpg",
                    desc: "lorem5 sdgfwfdgwdfgwd rwertwe,rgfwergew ",
                    category: "tadle",
                    price: "1125"
                },
                {
                    id: 3,
                    title: "Діван",
                    img: "sofa.jpg",
                    desc: "lorem5 sdgfwfdgwdfgwd rwertwe,rgfwergew ",
                    category: "sofa",
                    price: "23450"
                },
                {
                    id: 4,
                    title: "Кровать",
                    img: "bed.jpg",
                    desc: "lorem5 sdgfwfdgwdfgwd rwertwe,rgfwergew ",
                    category: "bed",
                    price: "6730"
                },
                {
                    id: 5,
                    title: "Шафа",
                    img: "wardrobe.jpg",
                    desc: "lorem5 sdgfwfdgwdfgwd rwertwe,rgfwergew ",
                    category: "wardrobe",
                    price: "15700"
                }

            ]
        }
        this.addToOrder = this.addToOrder(this)
    }

    render() {
        return (
            <div className='wrapper'>
                <Header orders={this.state.orders}/>
                <Items items = {this.state.items} onAdd={this.addToOrder}/>
                <Footer/>
            </div>
        )
    }
    addToOrder  (item){
       this.setState({orders:[...this.state.orders,item]})
    }
}

export default App;
